// ═══════════════════════════════════════════════
//  MEMORIES SECTION
// ═══════════════════════════════════════════════
function MemoriesSection({img1,img2,img3,img4}) {
  const [open,setOpen]=useState(false);
  const [trailStars,setTrailStars]=useState([]);
  const sectionRef=React.useRef(null);

  const bgStars=useMemo(()=>Array.from({length:50},(_,i)=>({id:i,size:Math.random()*2+1,top:Math.random()*100,left:Math.random()*100,d:(1.5+Math.random()*2).toFixed(1),dl:(Math.random()*3).toFixed(1)})),[]);

  const lastTrailTime=React.useRef(0);

  const spawnStars=(e,count=14)=>{
    const rect=sectionRef.current.getBoundingClientRect();
    const cx=(e.clientX!==undefined?e.clientX:(e.touches&&e.touches[0]?e.touches[0].clientX:rect.left+rect.width/2))-rect.left;
    const cy=(e.clientY!==undefined?e.clientY:(e.touches&&e.touches[0]?e.touches[0].clientY:rect.top+rect.height/2))-rect.top;
    const burst=Array.from({length:count},(_,i)=>({
      id:Date.now()+Math.random()+i, x:cx, y:cy,
      angle:(i/count)*360+Math.random()*30,
      dist:40+Math.random()*70,
      size:8+Math.random()*11,
      color:['#ffdd57','#ff9eb5','#b6d9ff','#ffe0ee','#fff4a0','#ffb6d9','#c8f0a0'][i%7],
      dur:0.6+Math.random()*0.5,
    }));
    setTrailStars(s=>[...s.slice(-120),...burst]);
    setTimeout(()=>setTrailStars(s=>s.filter(st=>!burst.find(n=>n.id===st.id))),1400);
  };

  const handleMove=(e)=>{
    const now=Date.now();
    if(now-lastTrailTime.current<80) return;
    lastTrailTime.current=now;
    spawnStars(e,7);
  };

  return (
    <div ref={sectionRef} onClick={e=>spawnStars(e,14)} onMouseMove={handleMove} onTouchMove={e=>{e.preventDefault();handleMove(e);}} onTouchStart={e=>spawnStars(e,14)}
      style={{background:"linear-gradient(135deg,#1a1a2e 0%,#16213e 50%,#0f3460 100%)",padding:"80px 20px",position:"relative",overflow:"hidden",cursor:"crosshair",userSelect:"none"}}>
      <style>{`
        @keyframes starShoot {
          0%   {transform:translate(0,0) scale(1) rotate(0deg);   opacity:1;}
          100% {transform:translate(var(--sx),var(--sy)) scale(0) rotate(var(--sr)); opacity:0;}
        }
        @keyframes trailDot {
          0%   {transform:translate(0,0) scale(0);opacity:0;}
          20%  {transform:translate(calc(var(--sx)*0.35),calc(var(--sy)*0.35)) scale(1.1);opacity:1;}
          100% {transform:translate(var(--sx),var(--sy)) scale(0);opacity:0;}
        }
      `}</style>
      {/* bg stars */}
      <div style={{position:"absolute",inset:0,pointerEvents:"none"}}>
        {bgStars.map(s=><div key={s.id} style={{position:"absolute",width:s.size,height:s.size,background:"white",borderRadius:"50%",top:`${s.top}%`,left:`${s.left}%`,animation:`blink ${s.d}s ease-in-out infinite ${s.dl}s`}} />)}
      </div>
      {/* star burst trail */}
      {trailStars.map(s=>{
        const rad=s.angle*Math.PI/180;
        const sx=Math.cos(rad)*s.dist+"px";
        const sy=Math.sin(rad)*s.dist+"px";
        const sr=(-90+Math.random()*180)+"deg";
        return (
          <div key={s.id} style={{position:"absolute",left:s.x,top:s.y,pointerEvents:"none",zIndex:20}}>
            <div style={{position:"absolute",width:s.size,height:s.size,marginLeft:-s.size/2,marginTop:-s.size/2,
              background:s.color,
              clipPath:"polygon(50% 0%,61% 35%,98% 35%,68% 57%,79% 91%,50% 70%,21% 91%,32% 57%,2% 35%,39% 35%)",
              filter:`drop-shadow(0 0 5px ${s.color})`,
              "--sx":sx,"--sy":sy,"--sr":sr,
              animation:`starShoot ${s.dur}s ease-out forwards`}} />
            <div style={{position:"absolute",width:s.size*0.4,height:s.size*0.4,marginLeft:-s.size*0.2,marginTop:-s.size*0.2,
              borderRadius:"50%",background:s.color,opacity:0.55,
              "--sx":`calc(${sx} * 0.6)`,"--sy":`calc(${sy} * 0.6)`,
              animation:`trailDot ${s.dur*0.75}s ease-out forwards`}} />
          </div>
        );
      })}
      <div style={{maxWidth:700,margin:"0 auto",textAlign:"center",position:"relative",zIndex:2}}>
        <p style={{fontSize:"0.72rem",letterSpacing:"0.28em",textTransform:"uppercase",color:"#f5c2c7",marginBottom:12}}>Chapter Six</p>
        <h2 style={{fontFamily:"'Playfair Display',serif",fontStyle:"italic",fontSize:"clamp(1.8rem,4vw,2.8rem)",color:"white",marginBottom:16}}>Memories</h2>
        <p style={{color:"rgba(255,255,255,0.6)",marginBottom:36,maxWidth:520,margin:"0 auto 36px"}}>Tap anywhere to make it sparkle ✨</p>
        <button onClick={e=>{e.stopPropagation();setOpen(o=>!o);}}
          style={{display:"inline-flex",alignItems:"center",gap:10,background:"transparent",border:"2px solid rgba(212,168,67,0.6)",color:"#d4a843",padding:"16px 36px",borderRadius:60,fontFamily:"'Playfair Display',serif",fontStyle:"italic",fontSize:"1.05rem",cursor:"pointer",transition:"all 0.3s"}}
          onMouseEnter={e=>{e.currentTarget.style.borderColor="#d4a843";e.currentTarget.style.color="white";}}
          onMouseLeave={e=>{e.currentTarget.style.borderColor="rgba(212,168,67,0.6)";e.currentTarget.style.color="#d4a843";}}>
          <span style={{fontSize:"1.3rem"}}>{open?"🌙":"🌸"}</span>
          {open?"Close memories":"Click to witness some of the memories"}
        </button>
        {open&&(
          <div style={{marginTop:48}} onClick={e=>e.stopPropagation()}>
            <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:16}}>
              {[img1,img2,img3,img4].map((src,i)=>(
                <div key={i} style={{background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:16,overflow:"hidden",aspectRatio:"3/4",position:"relative"}}>
                  <img src={src} alt="" style={{width:"100%",height:"100%",display:"block",objectFit:"cover"}} />
                  <div style={{position:"absolute",inset:0,background:"linear-gradient(to top,rgba(0,0,0,0.18) 0%,transparent 50%)",pointerEvents:"none"}} />
                </div>
              ))}
            </div>
            <button onClick={()=>setOpen(false)} style={{marginTop:28,background:"none",border:"1px solid rgba(255,255,255,0.15)",color:"rgba(255,255,255,0.4)",padding:"8px 22px",borderRadius:30,fontFamily:"'Lora',serif",fontSize:"0.8rem",fontStyle:"italic",cursor:"pointer"}}>close ↑</button>
          </div>
        )}
      </div>
    </div>
  );
}

const SHARED_KEY = "hana-comments-shared";

function formatTime(ts) {
  if (!ts) return "";
  const d = new Date(ts);
  return d.toLocaleString("en-US", { month: "short", day: "numeric", year: "numeric", hour: "numeric", minute: "2-digit", hour12: true });
}

function CommentsSection() {
  const [name,setName]=useState(null);
  const [text,setText]=useState("");
  const [messages,setMessages]=useState([]);
  const [loading,setLoading]=useState(true);
  const [saving,setSaving]=useState(false);
  const [toast,setToast]=useState("");
  const showToast=msg=>{setToast(msg);setTimeout(()=>setToast(""),3000);};
  const load=async()=>{setLoading(true);try{const r=await window.storage.get(SHARED_KEY,true);setMessages(r?JSON.parse(r.value):[]);}catch{setMessages([]);}setLoading(false);};
  useEffect(()=>{load();},[]);
  const submit=async()=>{
    if(!text.trim()||!name||saving)return;
    setSaving(true);
    const updated=[{text:text.trim(),author:name,ts:Date.now()},...messages];
    try{await window.storage.set(SHARED_KEY,JSON.stringify(updated),true);setMessages(updated);setText("");showToast(name==="Her"?"Her words are saved 💚":"Your words are saved 💛");}
    catch{showToast("Could not save  -  try again 🍃");}
    setSaving(false);
  };
  return (
    <div style={{background:"linear-gradient(180deg,#f0f7e8 0%,#fef9f0 100%)",padding:"80px 20px"}}>
      <div style={{maxWidth:700,margin:"0 auto"}}>
        <p style={{fontSize:"0.72rem",letterSpacing:"0.28em",textTransform:"uppercase",color:"#d4a843",marginBottom:12,textAlign:"center"}}>Just for the two of you</p>
        <h2 style={{fontFamily:"'Playfair Display',serif",fontStyle:"italic",color:"#2c1810",textAlign:"center"}}>Leave something here 🍃</h2>
        <p style={{textAlign:"center",maxWidth:500,margin:"0 auto 32px",color:"#6b4c3b"}}>This space belongs to both of you. Every message is shared  -  you will both see everything written here.</p>
        <div style={{display:"flex",gap:14,justifyContent:"center",marginBottom:32,flexWrap:"wrap"}}>
          {[["Him","Azeez is writing 💛"],["Her","She is writing 🍃"]].map(([val,label])=>(
            <button key={val} onClick={()=>setName(val)} style={{padding:"10px 26px",borderRadius:40,border:`2px solid ${name===val?"#2c1810":"#d4a843"}`,fontFamily:"'Playfair Display',serif",fontStyle:"italic",fontSize:"0.95rem",cursor:"pointer",background:name===val?"#2c1810":"white",color:name===val?"#fef9f0":"#2c1810"}}>{label}</button>
          ))}
        </div>
        {name&&(
          <div style={{background:"white",borderRadius:16,padding:28,boxShadow:"0 4px 40px rgba(0,0,0,0.07)",border:"1.5px solid rgba(212,168,67,0.2)",marginBottom:40}}>
            <textarea value={text} onChange={e=>setText(e.target.value.slice(0,500))} onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();submit();}}} placeholder={name==="Her"?"Dara k rakhna padta hai... or anything on your mind 💚":"Write something for her to find, Azeez 💛"} rows={5} style={{width:"100%",border:"none",outline:"none",fontFamily:"'Lora',serif",fontSize:"1rem",color:"#2c1810",background:"transparent",resize:"none",lineHeight:1.8}} />
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginTop:16,paddingTop:16,borderTop:"1px solid rgba(212,168,67,0.2)"}}>
              <span style={{fontSize:"0.78rem",color:"#c4a98a",fontStyle:"italic"}}>{text.length} / 500</span>
              <button onClick={submit} disabled={saving||!text.trim()} style={{background:"#2c1810",color:"#fef9f0",border:"none",padding:"10px 24px",borderRadius:40,fontFamily:"'Playfair Display',serif",fontStyle:"italic",fontSize:"0.92rem",cursor:"pointer",opacity:saving||!text.trim()?0.45:1}}>{saving?"Saving...":"Leave your words ✦"}</button>
            </div>
          </div>
        )}
        <button onClick={load} style={{display:"block",margin:"0 auto 24px",background:"none",border:"1px solid rgba(212,168,67,0.35)",color:"#d4a843",padding:"6px 20px",borderRadius:40,fontFamily:"'Lora',serif",fontSize:"0.8rem",cursor:"pointer",fontStyle:"italic"}}>↻ refresh</button>
        {loading?<p style={{textAlign:"center",color:"#c4a98a",fontStyle:"italic"}}>Loading...</p>
          :messages.length===0?<p style={{textAlign:"center",color:"#c4a98a",fontStyle:"italic"}}>No words yet  -  the page is waiting 🍃</p>
          :messages.map((m,i)=>(
            <div key={i} style={{background:"white",borderRadius:14,padding:"20px 24px",marginBottom:16,boxShadow:"0 2px 20px rgba(0,0,0,0.05)",borderLeft:`3px solid ${m.author==="Her"?"#5a8c4a":"#d4a843"}`}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:10,flexWrap:"wrap",gap:6}}>
                <span style={{fontFamily:"'Playfair Display',serif",fontStyle:"italic",fontSize:"0.85rem",color:m.author==="Her"?"#5a8c4a":"#d4a843"}}>{m.author==="Her"?"Hana 🍃":"Azeez 💛"}</span>
                <span style={{fontSize:"0.72rem",color:"#c4a98a",fontStyle:"italic"}}>{formatTime(m.ts)}</span>
              </div>
              <div style={{fontSize:"0.95rem",color:"#6b4c3b",lineHeight:1.85,whiteSpace:"pre-wrap",wordBreak:"break-word"}}>{m.text}</div>
            </div>
          ))}
      </div>
      {toast&&<div style={{position:"fixed",bottom:30,left:"50%",transform:"translateX(-50%)",background:"#2c1810",color:"#fef9f0",padding:"12px 28px",borderRadius:40,fontFamily:"'Playfair Display',serif",fontStyle:"italic",fontSize:"0.9rem",zIndex:9999}}>{toast}</div>}
    </div>
  );
}

